INSERT INTO `tours` VALUES (2,'El Nido Island Hopping','el-nido-island-hopping','Explore the stunning lagoons of El Nido. Testing Edit','El Nido Island Hopping is one of the most popular activities...','El Nido, named after the Spanish word for \"The Nest\"...','[\"Explore breathtaking lagoons by kayak\", \"Snorkel over vibrant coral reefs and marine life\", \"Enjoy grilled seafood lunch on a remote beach\", \"Swim through rock openings to find hidden coves\", \"Relax in serene turquoise waters surrounded by cliffs\"]','[\"Book tours ahead of time (Tour A and Tour C are most popular)\", \"Bring dry bags to protect electronics\", \"Use reef-safe sunscreen to protect marine life\", \"Wear aqua shoes or sandals with grip\"]','Abdulla Street, Barangay Maligaya, El Nido, Palawan 5313, Philippines',2200.00,50,'2025-06-03','2025-06-28','2025-05-23 09:48:49',0,0,0,NULL,'/images/el_nido.jpg',NULL),(4,'Vigan City Tour','vigan-city-tour','Wander through the cobbled streets of Vigan.','The Vigan City Tour takes you through cobblestone streets lined with preserved Spanish colonial houses and historical landmarks. It offers a glimpse into the Philippines’ colonial past and Ilocano culture.','Vigan is a UNESCO World Heritage City known for its well-preserved Spanish colonial architecture. Founded in the 16th century, it played a key role in trade and governance during the Spanish period.','[\"Walk along Calle Crisologo, a street frozen in time\", \"Visit museums such as Syquia Mansion and Crisologo Museum\", \"Ride a traditional kalesa (horse-drawn carriage)\", \"Taste authentic Ilocano dishes like empanada and bagnet\", \"Shop for local crafts and antiques\"]','[\"Wear comfortable walking shoes for cobbled streets\", \"Bring a hat or umbrella for sun protection\", \"Visit early morning or late afternoon to avoid crowds\", \"Respect local customs and heritage sites\"]','Ilocos Sur',1200.00,20,NULL,NULL,'2025-05-23 09:48:49',0,0,0,NULL,'/images/vigan_heritage_tour.png',NULL),(5,'Chocolate Hills Adventure','chocolate-hills-adventure','See Bohol’s iconic hills and ride an ATV.','The Chocolate Hills Adventure brings you to Bohol’s most iconic natural wonder. These geological formations are famous for their symmetrical, grass-covered hills that turn brown in the dry season.','The Chocolate Hills are a series of over 1,200 conical mounds formed by the uplift of coral deposits and erosion. They hold cultural significance and have inspired local legends.','[\"Climb the viewing deck at Carmen for panoramic views\", \"Ride an ATV through trails surrounding the hills\", \"Visit nearby attractions like Tarsier Sanctuary and Loboc River\", \"Take photos during sunrise or sunset for dramatic lighting\"]','[\"Wear light clothing and bring water for hiking up the view deck\", \"ATV rentals are available — bring valid ID and cash\", \"Visit during the dry season for the full “chocolate” effect\", \"Protect wildlife by following park rules and guides\"]','Bohol',1800.00,20,NULL,NULL,'2025-05-23 09:48:49',0,0,0,NULL,'/images/chocolate_hills.jpg',NULL),(6,'Siargao Surf Camp','siargao-surf-camp','Ride the waves and chill at Cloud 9.','Siargao Surf Camp is the ultimate destination for surf enthusiasts and beach lovers alike. Known for its laid-back vibe and powerful waves, this island offers a perfect blend of adventure and tranquility.','Siargao gained fame for its surf break “Cloud 9,” which attracted international surfers starting in the 1990s. Since then, it has become a hub for sustainable tourism and eco-conscious travel.','[\"Learn surfing from local instructors or challenge Cloud 9\", \"Island hop to Naked, Daku, and Guyam Islands\", \"Swim in the famous Magpupungko Rock Pools\", \"Bike through coconut tree-lined roads and rice fields\", \"Enjoy sunsets and bonfire nights with fellow travelers\"]','[\"Best surf season is September to November\", \"Bring reef booties and sunscreen\", \"Respect surf etiquette and local customs\", \"Book accommodations early during peak season\"]','Siargao',2500.00,20,NULL,NULL,'2025-05-23 09:48:49',0,0,0,NULL,'/images/siargao_surf_camp.jpg',NULL),(8,'testing tour admin','el-nido-island-hopping-test2','testing tour admin',NULL,NULL,NULL,NULL,'El Nido, Palawan, Philippines',3000.00,9,'2025-06-02','2025-06-27','2025-06-02 03:14:55',0,0,0,NULL,'el-nido-island-hopping-test2_el_nido.jpg',NULL),(9,'testing tour admin sencond time','el-nido-island-hopping-test3','testing tour admin second time',NULL,NULL,NULL,NULL,'El Nido, Palawan, Philippines',5000.00,20,'2025-06-02','2025-06-25','2025-06-02 04:19:15',0,0,0,NULL,'el-nido-island-hopping-test3_el_nido.jpg',NULL),(10,'testing tour admin test 4','el-nido-island-hopping-test4','asdf asdfas ',NULL,NULL,NULL,NULL,'El Nido, Palawan, Philippines',5000.00,25,'2025-06-02','2025-06-26','2025-06-02 15:23:00',0,0,0,NULL,'el-nido-island-hopping-test4_hero.png',NULL),(11,'Mount Fuji Spring Adventure','mount-fuji-spring-adventure','Mount Fuji Spring Adventure\r\nDiscover Japan’s iconic beauty with TourWise\r\n\r\nExperience the breathtaking view of Mount Fuji framed by blooming cherry blossoms. Whether you\'re sightseeing from Lake Kawaguchi or exploring nearby cultural towns, this journey promises serenity, adventure, and unforgettable memories.\r\n\r\n🗻 Location: Yamanashi Prefecture, Japan\r\n🌸 Best Time to Visit: March–May (Cherry Blossom Season)\r\n📅 Tour Duration: Full-Day or 2-Day Packages\r\n🎒 Inclusions: Guided tour, cultural stops, photo sessions, and local snacks\r\n\r\n🔗 www.tourwise.com | 📧 hello@tourwise.com | 📞 +81 90 1234 5678',NULL,NULL,NULL,NULL,'Yamanashi Prefecture, Japan',12800.85,25,'2025-06-06','2025-06-30','2025-06-06 02:06:52',0,0,0,NULL,'mount-fuji-spring-adventure_tourwise_mt_fuji2.png',NULL),(12,'Cliff Diving Thrill - Dauis Escape','cliff-diving-dauis-bohol','Leap into adventure! Experience the thrill of cliff diving off Dauis\' scenic coast. With professional guides, safety gear, and crystal-clear waters below, this half-day tour is perfect for adrenaline lovers and nature enthusiasts alike.',NULL,NULL,NULL,NULL,'Dauis, Bohol, Philippines',950.00,30,'2025-06-06','2025-06-30','2025-06-06 02:23:54',0,0,0,NULL,'cliff-diving-dauis-bohol_cliffdive.png',NULL),(13,'Puerto Princesa All-In Package','puerto-princesa-all-in','Explore the natural wonders of Puerto Princesa with this hassle-free all-in package! Enjoy 3 days and 2 nights of guided adventures, comfortable accommodations, roundtrip flights, and smooth transfers. Discover limestone cliffs, emerald waters, and the famous Underground River in one unforgettable Palawan escape.\r\n\r\n',NULL,NULL,NULL,NULL,'Puerto Princesa, Palawan, Philippines',6888.00,23,'2025-06-06','2025-06-30','2025-06-06 04:19:09',0,0,0,NULL,'puerto-princesa-all-in_puerto_princesa_package.png',NULL),(14,'Countryside Escape','countryside-escape','Relax and reconnect with nature as you explore lush fields, quiet villages, and rolling hills. Perfect for those seeking peace, fresh air, and cultural charm.',NULL,NULL,NULL,NULL,'Benguet Highlands, Philippines',2499.00,25,'2025-06-16','2025-06-28','2025-06-16 07:26:46',0,0,0,NULL,'countryside-escape_countryside-escape_green_hills_lodge.png',1),(15,'El-Nido','el-nido-island-hopping123','sdsdfsdfsdf',NULL,NULL,NULL,NULL,'El Nido, Palawan, Philippines',3244.00,31,'2025-06-16','2025-06-28','2025-06-16 07:50:15',0,0,0,NULL,'el-nido-island-hopping123_el_nido.jpg',1);
